import{_ as a,o as t,c as o,ag as n}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"04 — Figma Workflow: How Designers Work in Figma","description":"","frontmatter":{},"headers":[],"relativePath":"04-figma-workflow.md","filePath":"04-figma-workflow.md"}'),i={name:"04-figma-workflow.md"};function s(r,e,d,l,c,h){return t(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="_04-—-figma-workflow-how-designers-work-in-figma" tabindex="-1">04 — Figma Workflow: How Designers Work in Figma <a class="header-anchor" href="#_04-—-figma-workflow-how-designers-work-in-figma" aria-label="Permalink to &quot;04 — Figma Workflow: How Designers Work in Figma&quot;">​</a></h1><p>This guide explains how Figma is used in the Synapse, how to navigate the design file, and — most importantly — how to get the information you need to implement a component in code.</p><p>You don&#39;t need to be a designer to follow this guide. Developers use Figma constantly: to understand what a component should look like, to find the right CSS values, and to get Figma node URLs for Claude.</p><hr><h2 id="figma-basics" tabindex="-1">Figma Basics <a class="header-anchor" href="#figma-basics" aria-label="Permalink to &quot;Figma Basics&quot;">​</a></h2><p>Before diving into the MDT file, a quick vocabulary lesson.</p><h3 id="frames" tabindex="-1">Frames <a class="header-anchor" href="#frames" aria-label="Permalink to &quot;Frames&quot;">​</a></h3><p>A frame is a container — like a div in HTML, or an artboard in older design tools. Components, sections, and entire screens live inside frames. You&#39;ll recognize frames in the sidebar because they have a small hashtag-like icon next to their name.</p><h3 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h3><p>A component in Figma is a reusable design element — the equivalent of a React component. When a designer creates a Button component in Figma, it&#39;s a master template. Every button you see on other pages is an &quot;instance&quot; of that component. Change the master, and all instances update.</p><p>Components appear in the sidebar with a purple diamond icon.</p><h3 id="variants" tabindex="-1">Variants <a class="header-anchor" href="#variants" aria-label="Permalink to &quot;Variants&quot;">​</a></h3><p>Variants are like different props on a React component. A Button component might have variants for:</p><ul><li><strong>Style:</strong> Primary, Secondary, Tertiary, Danger, Ghost</li><li><strong>Size:</strong> SM, MD, LG, XL</li><li><strong>State:</strong> Enabled, Hover, Focused, Disabled</li><li><strong>Type:</strong> Text only, Text + Icon, Icon only</li></ul><p>In Figma, all these variants live together in a &quot;component set&quot; — a grid showing every combination.</p><h3 id="auto-layout" tabindex="-1">Auto Layout <a class="header-anchor" href="#auto-layout" aria-label="Permalink to &quot;Auto Layout&quot;">​</a></h3><p>Auto Layout is Figma&#39;s version of CSS Flexbox. When a frame has Auto Layout, its children are laid out automatically based on direction, spacing, and alignment settings. This is how Figma can show you the exact padding and gap values that should go in your CSS.</p><hr><h2 id="opening-the-synapse-figma-file" tabindex="-1">Opening the Synapse Figma File <a class="header-anchor" href="#opening-the-synapse-figma-file" aria-label="Permalink to &quot;Opening the Synapse Figma File&quot;">​</a></h2><p>The design file is at:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>figma.com/design/A8iOt3oQHHT20N1mSpxnQ1/Components--Copy-</span></span></code></pre></div><p>Open it in your browser or Figma desktop app. You&#39;ll need to be logged in with a Figma account that has been granted access to the file.</p><p><strong>To bookmark it:</strong> Click the star icon next to the file name in Figma to add it to your Figma home screen.</p><hr><h2 id="how-the-file-is-structured" tabindex="-1">How the File Is Structured <a class="header-anchor" href="#how-the-file-is-structured" aria-label="Permalink to &quot;How the File Is Structured&quot;">​</a></h2><h3 id="pages" tabindex="-1">Pages <a class="header-anchor" href="#pages" aria-label="Permalink to &quot;Pages&quot;">​</a></h3><p>The file uses multiple pages (listed in the left panel at the very top). Common pages include:</p><ul><li><strong>Components</strong> — the main page with all UI components</li><li><strong>Tokens</strong> or <strong>Variables</strong> — color palettes, spacing scales, typography styles</li><li><strong>Playground</strong> — scratch area for exploring designs</li><li><strong>Archive</strong> — older designs kept for reference</li></ul><p>Click on a page name in the left panel to navigate to it.</p><h3 id="the-layers-sidebar" tabindex="-1">The Layers Sidebar <a class="header-anchor" href="#the-layers-sidebar" aria-label="Permalink to &quot;The Layers Sidebar&quot;">​</a></h3><p>On the left side of the Figma screen, you&#39;ll see the Layers panel. This shows the hierarchy of every element on the current page. It&#39;s organized like a tree:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Page</span></span>
<span class="line"><span>  Frame: Button Component Set</span></span>
<span class="line"><span>    Variant: Style=Primary, Size=MD, State=Enabled</span></span>
<span class="line"><span>    Variant: Style=Primary, Size=MD, State=Hover</span></span>
<span class="line"><span>    Variant: Style=Secondary, Size=MD, State=Enabled</span></span>
<span class="line"><span>    ...</span></span></code></pre></div><p>You can expand items by clicking the triangle next to them.</p><h3 id="finding-the-button-component" tabindex="-1">Finding the Button Component <a class="header-anchor" href="#finding-the-button-component" aria-label="Permalink to &quot;Finding the Button Component&quot;">​</a></h3><ol><li>Open the Components page</li><li>In the search bar at the top of the layers panel, type &quot;Button&quot;</li><li>Click on the Button component set in the results</li><li>The canvas will zoom to show the Button variants</li></ol><p>Alternatively, press <code>Cmd+F</code> (or <code>Ctrl+F</code>) to open a global search and type &quot;Button.&quot;</p><hr><h2 id="how-variants-are-named-in-figma" tabindex="-1">How Variants Are Named in Figma <a class="header-anchor" href="#how-variants-are-named-in-figma" aria-label="Permalink to &quot;How Variants Are Named in Figma&quot;">​</a></h2><p>In Figma, variants are named using a <code>Property=Value</code> format. For example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Style=Primary, Type=Text+Icon, Size=MD, State=Enabled</span></span></code></pre></div><p>This tells you exactly what a variant represents. The names map directly to code props:</p><table tabindex="0"><thead><tr><th>Figma Variant Name</th><th>Code Prop</th></tr></thead><tbody><tr><td><code>Style=Primary</code></td><td><code>variant=&quot;primary&quot;</code></td></tr><tr><td><code>Style=Secondary</code></td><td><code>variant=&quot;secondary&quot;</code></td></tr><tr><td><code>Style=Tertiary</code></td><td><code>variant=&quot;tertiary&quot;</code></td></tr><tr><td><code>Style=Danger</code></td><td><code>variant=&quot;danger&quot;</code></td></tr><tr><td><code>Style=Ghost</code></td><td><code>variant=&quot;ghost&quot;</code></td></tr><tr><td><code>Size=SM</code></td><td><code>size=&quot;sm&quot;</code></td></tr><tr><td><code>Size=MD</code></td><td><code>size=&quot;md&quot;</code></td></tr><tr><td><code>Size=LG</code></td><td><code>size=&quot;lg&quot;</code></td></tr><tr><td><code>Size=XL</code></td><td><code>size=&quot;xl&quot;</code></td></tr><tr><td><code>State=Disabled</code></td><td><code>disabled={true}</code></td></tr><tr><td><code>State=Loading</code></td><td><code>loading={true}</code></td></tr></tbody></table><p>The convention is lowercase in code even when Figma uses uppercase. Spaces and special characters in Figma variant names are removed or replaced in code.</p><hr><h2 id="how-to-copy-a-figma-node-url-—-critical-step" tabindex="-1">How to Copy a Figma Node URL — Critical Step <a class="header-anchor" href="#how-to-copy-a-figma-node-url-—-critical-step" aria-label="Permalink to &quot;How to Copy a Figma Node URL — Critical Step&quot;">​</a></h2><p>A Figma node URL is a link that points directly to a specific element in the Figma file. You&#39;ll use these constantly when asking Claude to implement components.</p><h3 id="method-1-right-click-on-any-element" tabindex="-1">Method 1: Right-Click on Any Element <a class="header-anchor" href="#method-1-right-click-on-any-element" aria-label="Permalink to &quot;Method 1: Right-Click on Any Element&quot;">​</a></h3><ol><li>Click once on a component (or any element) in the canvas</li><li>Right-click on it</li><li>In the context menu, click <strong>Copy link to selection</strong></li><li>The URL is now in your clipboard</li></ol><h3 id="method-2-from-the-browser-address-bar" tabindex="-1">Method 2: From the Browser Address Bar <a class="header-anchor" href="#method-2-from-the-browser-address-bar" aria-label="Permalink to &quot;Method 2: From the Browser Address Bar&quot;">​</a></h3><p>When you click on any element in Figma (in the browser), the URL in the address bar updates to include the node ID:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.figma.com/design/A8iOt3oQHHT20N1mSpxnQ1/Components--Copy-?node-id=2022-2455</span></span></code></pre></div><p>The <code>node-id=2022-2455</code> part is what identifies the specific element. You can copy the entire URL from the address bar.</p><h3 id="example-node-url" tabindex="-1">Example Node URL <a class="header-anchor" href="#example-node-url" aria-label="Permalink to &quot;Example Node URL&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.figma.com/design/A8iOt3oQHHT20N1mSpxnQ1/Components--Copy-?node-id=2022-2455</span></span></code></pre></div><p>Breaking it down:</p><ul><li><code>A8iOt3oQHHT20N1mSpxnQ1</code> — the file ID (always the same for this file)</li><li><code>Components--Copy-</code> — the file name (cosmetic, doesn&#39;t affect the link)</li><li><code>node-id=2022-2455</code> — the specific element within the file</li></ul><h3 id="when-to-use-node-urls" tabindex="-1">When to Use Node URLs <a class="header-anchor" href="#when-to-use-node-urls" aria-label="Permalink to &quot;When to Use Node URLs&quot;">​</a></h3><ul><li>When asking Claude to implement a component: paste the URL of the component set (not an individual variant)</li><li>When asking Claude to set up Code Connect: paste the URL of the master component</li><li>When reporting a design issue to a teammate: paste the URL so they go to the exact element</li></ul><hr><h2 id="how-to-use-dev-mode-in-figma" tabindex="-1">How to Use Dev Mode in Figma <a class="header-anchor" href="#how-to-use-dev-mode-in-figma" aria-label="Permalink to &quot;How to Use Dev Mode in Figma&quot;">​</a></h2><p>Dev Mode is a special view designed for developers. It shows exact CSS values, spacing, and design tokens — much more useful than the default designer view.</p><h3 id="enabling-dev-mode" tabindex="-1">Enabling Dev Mode <a class="header-anchor" href="#enabling-dev-mode" aria-label="Permalink to &quot;Enabling Dev Mode&quot;">​</a></h3><p>Click the <strong>Dev Mode</strong> toggle in the top-right toolbar of Figma. It looks like a <code>&lt;/&gt;</code> icon.</p><p>Keyboard shortcut: <code>Shift+D</code></p><p>You&#39;ll notice the UI changes — the interface shifts to a developer-focused layout.</p><h3 id="what-you-can-see-in-dev-mode" tabindex="-1">What You Can See in Dev Mode <a class="header-anchor" href="#what-you-can-see-in-dev-mode" aria-label="Permalink to &quot;What You Can See in Dev Mode&quot;">​</a></h3><p><strong>When you click on a component:</strong></p><ul><li><strong>Dimensions:</strong> Width and height in pixels</li><li><strong>Fill:</strong> The background color — shown as a token name if tokens are configured (e.g., <code>--ds-core-black</code>) or as a hex value</li><li><strong>Typography:</strong> Font family, size, weight, line height, letter spacing</li><li><strong>Spacing:</strong> Padding and gap values from Auto Layout</li><li><strong>Radius:</strong> Border radius values</li><li><strong>Shadows and borders:</strong> Box shadow and border definitions</li></ul><p><strong>The Inspect Panel (right sidebar in Dev Mode):</strong></p><p>Scroll down in the right panel to see a &quot;Code&quot; section that shows CSS-like values:</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* Example from a Button */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">display: flex;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">align-items</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: center;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">padding: 8px 16px;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gap: 8px;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">border-radius</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: 4px;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">background: var(--ds-brand-primary);</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">font-family</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: Inter;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">font-size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: 14px;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">font-weight</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: 500;</span></span></code></pre></div><p>These values are what you use when writing your CSS Module file.</p><p><strong>Important:</strong> When Figma shows a hex value like <code>#0052CC</code>, look for the corresponding CSS variable in the design tokens. You should use the variable (e.g., <code>var(--ds-brand-primary)</code>), not the hardcoded hex color. More on this below.</p><hr><h2 id="how-to-check-design-tokens-in-figma" tabindex="-1">How to Check Design Tokens in Figma <a class="header-anchor" href="#how-to-check-design-tokens-in-figma" aria-label="Permalink to &quot;How to Check Design Tokens in Figma&quot;">​</a></h2><p>Design tokens are the named values behind colors, spacing, and typography. In the Synapse, tokens are CSS custom properties that start with <code>--ds-</code> or <code>--color-</code>.</p><h3 id="finding-tokens-in-figma" tabindex="-1">Finding Tokens in Figma <a class="header-anchor" href="#finding-tokens-in-figma" aria-label="Permalink to &quot;Finding Tokens in Figma&quot;">​</a></h3><p><strong>Variables panel:</strong></p><ol><li>In Figma, click the Variables icon in the right sidebar (it looks like two stacked rectangles or a grid)</li><li>Or: use Edit → Show Variables Panel</li><li>You&#39;ll see collections like &quot;Colors,&quot; &quot;Spacing,&quot; &quot;Radius&quot;</li></ol><p><strong>When inspecting an element in Dev Mode:</strong> If tokens are applied in Figma, the inspect panel will show the token name next to color values. For example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Fill: ds-core-black   #000000</span></span></code></pre></div><p>This tells you to use <code>var(--ds-core-black)</code> in your CSS, not <code>#000000</code>.</p><h3 id="token-name-to-css-variable-mapping" tabindex="-1">Token Name to CSS Variable Mapping <a class="header-anchor" href="#token-name-to-css-variable-mapping" aria-label="Permalink to &quot;Token Name to CSS Variable Mapping&quot;">​</a></h3><p>The naming convention is direct:</p><table tabindex="0"><thead><tr><th>Figma Token Name</th><th>CSS Variable</th></tr></thead><tbody><tr><td><code>ds-core-black</code></td><td><code>var(--ds-core-black)</code></td></tr><tr><td><code>ds-brand-primary</code></td><td><code>var(--ds-brand-primary)</code></td></tr><tr><td><code>ds-neutral-20</code></td><td><code>var(--ds-neutral-20)</code></td></tr><tr><td><code>ds-success</code></td><td><code>var(--ds-success)</code></td></tr><tr><td><code>ds-warning</code></td><td><code>var(--ds-warning)</code></td></tr><tr><td><code>ds-danger</code></td><td><code>var(--ds-danger)</code></td></tr><tr><td><code>ds-text-para</code></td><td><code>var(--ds-text-para)</code></td></tr></tbody></table><p>The CSS variables are defined in <code>src/styles/tokens.css</code> in the codebase. When you need to verify a variable name, open that file.</p><p><strong>Rule:</strong> Always use the CSS variable. Never paste hex values into your CSS.</p><hr><h2 id="naming-conventions-for-new-components" tabindex="-1">Naming Conventions for New Components <a class="header-anchor" href="#naming-conventions-for-new-components" aria-label="Permalink to &quot;Naming Conventions for New Components&quot;">​</a></h2><p>Consistency in naming makes everything easier — Figma to code to Storybook to ZeroHeight.</p><h3 id="component-names" tabindex="-1">Component Names <a class="header-anchor" href="#component-names" aria-label="Permalink to &quot;Component Names&quot;">​</a></h3><ul><li><strong>PascalCase</strong> everywhere: <code>Button</code>, <code>InputField</code>, <code>DataTable</code>, <code>Badge</code>, <code>Modal</code></li><li>The Figma component name, the file name, the TypeScript export, and the Storybook title should all match</li></ul><h3 id="prop-names" tabindex="-1">Prop Names <a class="header-anchor" href="#prop-names" aria-label="Permalink to &quot;Prop Names&quot;">​</a></h3><ul><li><strong>camelCase</strong> for all props: <code>variant</code>, <code>size</code>, <code>isLoading</code>, <code>onClick</code>, <code>leftIcon</code></li><li>Booleans: prefer plain names that read naturally (<code>disabled</code>, <code>loading</code>, not <code>isDisabled</code>, <code>isLoading</code>)</li><li>Event handlers: always start with <code>on</code>: <code>onClick</code>, <code>onChange</code>, <code>onBlur</code></li></ul><h3 id="css-class-names-in-module-css-files" tabindex="-1">CSS Class Names in .module.css Files <a class="header-anchor" href="#css-class-names-in-module-css-files" aria-label="Permalink to &quot;CSS Class Names in .module.css Files&quot;">​</a></h3><ul><li><strong>camelCase</strong> for multi-word names: <code>.iconLeft</code>, <code>.loadingSpinner</code>, <code>.primaryVariant</code></li><li>Single words: plain lowercase: <code>.root</code>, <code>.primary</code>, <code>.disabled</code></li><li>State classes: match the prop name: <code>.loading</code>, <code>.disabled</code>, <code>.focused</code></li></ul><h3 id="figma-variant-name-to-css-class-name" tabindex="-1">Figma Variant Name to CSS Class Name <a class="header-anchor" href="#figma-variant-name-to-css-class-name" aria-label="Permalink to &quot;Figma Variant Name to CSS Class Name&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Figma</th><th>CSS class</th></tr></thead><tbody><tr><td><code>Style=Primary</code></td><td><code>.primary</code></td></tr><tr><td><code>Size=MD</code></td><td><code>.md</code></td></tr><tr><td><code>Type=Text+Icon</code></td><td>(use conditional rendering, not a class)</td></tr><tr><td><code>State=Disabled</code></td><td><code>.disabled</code> or handled via <code>[disabled]</code> attribute</td></tr></tbody></table><hr><h2 id="how-to-add-a-new-component-to-figma-for-designers" tabindex="-1">How to Add a New Component to Figma (for Designers) <a class="header-anchor" href="#how-to-add-a-new-component-to-figma-for-designers" aria-label="Permalink to &quot;How to Add a New Component to Figma (for Designers)&quot;">​</a></h2><p>This section is for designers creating new components that will be implemented in code.</p><h3 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h3><ol><li><p><strong>Create a frame</strong> for your component (press <code>F</code> and draw a frame, or press <code>A</code> and choose a frame size)</p></li><li><p><strong>Design the component</strong> inside the frame</p></li><li><p><strong>Make it a component:</strong> Select the frame → press <code>Cmd+Alt+K</code> (Mac) or <code>Ctrl+Alt+K</code> (Windows) The frame turns purple with a diamond icon — it&#39;s now a Figma component</p></li><li><p><strong>Name it properly:</strong> In the right panel, give it a PascalCase name matching the code component (e.g., <code>Badge</code>)</p></li><li><p><strong>Add variants:</strong> Click the purple &quot;+&quot; icon next to your component to add variants Name variants using the <code>Property=Value</code> format:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Style=Default, Size=MD, State=Enabled</span></span></code></pre></div></li><li><p><strong>Apply design tokens:</strong> For all colors, use Figma variables from the token library (not raw hex values). This ensures the CSS variable names appear in Dev Mode for developers.</p></li><li><p><strong>Publish to the team library:</strong> In the Assets panel, click the library icon → click &quot;Publish changes&quot; Publishing makes the component available for Code Connect and for use in other Figma files.</p></li></ol><h3 id="tips-for-designer-developer-handoff" tabindex="-1">Tips for Designer-Developer Handoff <a class="header-anchor" href="#tips-for-designer-developer-handoff" aria-label="Permalink to &quot;Tips for Designer-Developer Handoff&quot;">​</a></h3><ul><li>Write clear variant descriptions in the component&#39;s annotation notes</li><li>Make sure Auto Layout is applied correctly so spacing values are accurate</li><li>Use the correct token names for all colors and spacing</li><li>Test the component in both light and dark color modes if applicable</li></ul><hr><h2 id="quick-reference" tabindex="-1">Quick Reference <a class="header-anchor" href="#quick-reference" aria-label="Permalink to &quot;Quick Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Task</th><th>What to do in Figma</th></tr></thead><tbody><tr><td>Find a component</td><td>Cmd+F → type component name</td></tr><tr><td>Get node URL</td><td>Right-click element → Copy link to selection</td></tr><tr><td>See CSS values</td><td>Enable Dev Mode (Shift+D) → click element</td></tr><tr><td>Find token names</td><td>Dev Mode → inspect panel → look for variable names next to color values</td></tr><tr><td>See component variants</td><td>Click component set → see grid of variants in canvas</td></tr><tr><td>Check spacing</td><td>Dev Mode → hover between elements to see spacing values</td></tr><tr><td>Check dark mode</td><td>In the right panel, switch the color mode variable</td></tr></tbody></table><hr><p>Next: <a href="./05-clone-and-run">05 — Clone &amp; Run</a> — Download the project and run Storybook on your machine.</p>`,110)])])}const g=a(i,[["render",s]]);export{m as __pageData,g as default};
